import React from 'react';
import { useData } from '../../context/DataContext';
import { useAuth } from '../../context/AuthContext';

const Reports = () => {
  const { user } = useAuth();
  const { tasks, staffList, facilityLogs } = useData();
  const isChief = user?.role === 'chief';

  // --- LOGIC TÍNH THU NHẬP (Demo) ---
  const calculateIncome = (staff) => {
      // Công thức: UBI 1 thực + UBI 2 thực + Remuneration
      const ubi1 = (staff.ubi1Base || 0) * (staff.ubi1Percent || 0) / 100;
      const ubi2 = (staff.ubi2Base || 0) * (staff.ubi2Percent || 0) / 100;
      return ubi1 + ubi2 + (staff.remuneration || 0);
  };

  const totalCompanyIncome = staffList.reduce((acc, s) => acc + calculateIncome(s), 0);

  return (
    <div style={{ padding: '20px' }}>
      <h2>Báo cáo Tổng hợp</h2>

      {/* 1. BÁO CÁO CSVC (MỚI) */}
      <div style={{ marginBottom: '30px', background: 'white', padding: '15px', borderRadius: '8px' }}>
          <h3 style={{ color: '#003366' }}>Tình trạng CSVC</h3>
          <table border="1" style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem' }}>
             <thead><tr style={{background:'#eee'}}><th>Thời gian</th><th>Khu vực</th><th>Người check</th><th>Hạng mục</th><th>Trạng thái</th></tr></thead>
             <tbody>
                {facilityLogs.sort((a,b) => new Date(b.timestamp) - new Date(a.timestamp)).map(log => (
                    <tr key={log.id}>
                        <td>{new Date(log.timestamp).toLocaleString()}</td>
                        <td>{log.area} ({log.type})</td>
                        <td>{log.staffName}</td>
                        <td>{log.item}</td>
                        <td style={{color: log.status.includes('Tốt') || log.status.includes('Mát') ? 'green' : 'red'}}>{log.status}</td>
                    </tr>
                ))}
             </tbody>
          </table>
      </div>

      {/* 2. TỔNG THU NHẬP (CHIEF ONLY) */}
      {isChief && (
          <div style={{ marginBottom: '30px', background: '#f0fdf4', padding: '15px', borderRadius: '8px', border: '1px solid #bbf7d0' }}>
              <h3 style={{ color: '#166534' }}>Tài chính & Thu nhập (Chief Admin)</h3>
              <h1 style={{ marginTop: 0 }}>Tổng chi lương: {totalCompanyIncome.toLocaleString()} VNĐ</h1>
              
              <details>
                  <summary style={{cursor:'pointer', fontWeight:'bold'}}>Chi tiết theo nhân sự</summary>
                  <table style={{width:'100%', marginTop:'10px', background:'white'}}>
                      <thead><tr style={{textAlign:'left'}}><th>Nhân sự</th><th>Tổng nhận</th></tr></thead>
                      <tbody>
                          {staffList.map(s => (
                              <tr key={s.id} style={{borderBottom:'1px solid #eee'}}>
                                  <td>{s.name}</td>
                                  <td>{calculateIncome(s).toLocaleString()} VNĐ</td>
                              </tr>
                          ))}
                      </tbody>
                  </table>
              </details>
          </div>
      )}
      
      {/* 3. BÁO CÁO TASK CŨ GIỮ NGUYÊN... */}
    </div>
  );
};

export default Reports;
